import{_ as t,o as a,c as s,ak as o}from"./chunks/framework.sV-XtlWr.js";const g=JSON.parse('{"title":"Desktop app","description":"","frontmatter":{"title":"Desktop app","lang":"en-US"},"headers":[],"relativePath":"desktop.md","filePath":"desktop.md","lastUpdated":1784833541000}'),n={name:"desktop.md"};function r(i,e,d,l,p,h){return a(),s("div",null,[...e[0]||(e[0]=[o(`<h1 id="desktop-app" tabindex="-1">Desktop app <a class="header-anchor" href="#desktop-app" aria-label="Permalink to &quot;Desktop app&quot;">​</a></h1><p>The Piwi Dashboard desktop app runs the <strong>entire dashboard on your machine</strong> — no Docker, no <code>npx</code>, no server to set up. It bundles the same server that ships as the Docker image, wraps it in a native window, and keeps your data in a local folder. It&#39;s ideal for a single developer who runs Playwright locally and wants permanent history, flaky scoring, failure clustering, and locator healing without standing up a server.</p><blockquote><p>Everything binds to <code>127.0.0.1</code> — the app is local-only and nothing is exposed to the network.</p></blockquote><h2 id="download" tabindex="-1">Download <a class="header-anchor" href="#download" aria-label="Permalink to &quot;Download&quot;">​</a></h2><p>Grab the installer for your OS from the <a href="https://github.com/PiwiTests/platform/releases/latest" target="_blank" rel="noreferrer">latest release</a>:</p><table tabindex="0"><thead><tr><th>OS</th><th>Installer</th></tr></thead><tbody><tr><td><strong>Windows</strong></td><td><code>.msi</code></td></tr><tr><td><strong>macOS</strong> (Apple silicon)</td><td><code>.dmg</code></td></tr></tbody></table><p>Linux is not packaged yet — use <a href="/deployment.html">Docker or <code>npx</code></a> there.</p><h3 id="unsigned-builds" tabindex="-1">Unsigned builds <a class="header-anchor" href="#unsigned-builds" aria-label="Permalink to &quot;Unsigned builds&quot;">​</a></h3><p>Until code-signing certificates are in place the installers are <strong>unsigned</strong>, so your OS shows a first-run warning:</p><ul><li><strong>macOS:</strong> right-click the app → <strong>Open</strong> → <strong>Open</strong> (once).</li><li><strong>Windows:</strong> SmartScreen → <strong>More info</strong> → <strong>Run anyway</strong>.</li></ul><h2 id="where-your-data-lives" tabindex="-1">Where your data lives <a class="header-anchor" href="#where-your-data-lives" aria-label="Permalink to &quot;Where your data lives&quot;">​</a></h2><p>Open <strong>Settings → Storage → Data location</strong> to see the exact paths, or use the tray menu&#39;s <strong>Open data folder</strong>. By default everything sits under the OS app-data directory:</p><table tabindex="0"><thead><tr><th>OS</th><th>Location</th></tr></thead><tbody><tr><td><strong>Windows</strong></td><td><code>%APPDATA%\\io.piwitests.dashboard\\.data</code></td></tr><tr><td><strong>macOS</strong></td><td><code>~/Library/Application Support/io.piwitests.dashboard/.data</code></td></tr></tbody></table><p>That folder holds <code>piwi.db</code> (SQLite) and <code>storage/</code> (reports, traces, attachments). Back it up by copying the folder while the app is closed.</p><h2 id="running-in-the-background" tabindex="-1">Running in the background <a class="header-anchor" href="#running-in-the-background" aria-label="Permalink to &quot;Running in the background&quot;">​</a></h2><p>By default, closing the window quits the app. From the tray icon you can enable:</p><ul><li><strong>Run in background</strong> — closing the window keeps the server running in the tray, so submitting more results is instant and reopening is immediate.</li><li><strong>Start on login</strong> — launch the app (hidden, into the tray) when you log in.</li></ul><h2 id="sending-results-to-it" tabindex="-1">Sending results to it <a class="header-anchor" href="#sending-results-to-it" aria-label="Permalink to &quot;Sending results to it&quot;">​</a></h2><p>The desktop app protects its local API with an <strong>access token</strong>, so the reporter must present it. Open <strong>Settings → Storage → Send results to this app</strong> to copy your token and a ready-made snippet, then set it as the reporter&#39;s <code>apiKey</code>:</p><div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;@piwitests/reporter&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  serverUrl: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;http://localhost:3000&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  projectName: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;my-project&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  apiKey: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;pd_…&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// from Settings → Storage (or the PIWI_API_KEY env var)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}]</span></span></code></pre></div><p>The token is a <strong>local secret</strong> — prefer the <code>PIWI_API_KEY</code> env var over committing it. The app uses port <strong>3000</strong> by default (falling back to another local port only if 3000 is already taken — the window&#39;s address bar shows the actual one).</p><blockquote><p><strong>Why a token?</strong> The server binds <code>127.0.0.1</code>, which blocks other machines — but loopback alone doesn&#39;t stop <em>other local processes</em> or <em>web pages open in your browser</em> from reaching it. The token means only the app itself and tools you&#39;ve handed it to (your reporter) can submit or read. Accepting results from <em>other machines</em> over the network is intentionally not supported in the desktop build — run the <a href="/deployment.html">Docker image</a> for a shared, always-on server.</p></blockquote><h2 id="building-from-source" tabindex="-1">Building from source <a class="header-anchor" href="#building-from-source" aria-label="Permalink to &quot;Building from source&quot;">​</a></h2><p>See <a href="https://github.com/PiwiTests/platform/blob/main/desktop/README.md" target="_blank" rel="noreferrer"><code>desktop/README.md</code></a> for the local build steps (Node 24+, the Rust toolchain, and the Tauri system dependencies).</p>`,24)])])}const u=t(n,[["render",r]]);export{g as __pageData,u as default};
